import logging
import os
import re
from datetime import datetime
from typing import Dict, Any
import json

class SecureLogger:
    def __init__(self, log_file: str = "app.log"):
        self.log_file = log_file
        self.logger = logging.getLogger("SecureLogger")
        self.logger.setLevel(logging.INFO)
        
        # Prevent log injection patterns
        self.log_injection_pattern = re.compile(
            r'[\r\n\t\x00-\x1f\x7f-\x9f]',
            re.IGNORECASE
        )
        
        # Create file handler with proper permissions
        if not os.path.exists(log_file):
            os.makedirs(os.path.dirname(log_file) if os.path.dirname(log_file) else '.', exist_ok=True)
            with open(log_file, 'w') as f:
                pass
        
        # Set secure file permissions
        os.chmod(log_file, 0o600)
        
        handler = logging.FileHandler(log_file)
        formatter = logging.Formatter(
            '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
        )
        handler.setFormatter(formatter)
        self.logger.addHandler(handler)
    
    def sanitize_message(self, message: str) -> str:
        """Remove or escape potentially dangerous characters"""
        if not isinstance(message, str):
            message = str(message)
        
        # Remove or replace problematic characters
        sanitized = self.log_injection_pattern.sub('', message)
        
        # Escape JSON special characters
        sanitized = sanitized.replace('"', '\\"')
        sanitized = sanitized.replace('\\', '\\\\')
        
        return sanitized
    
    def log_request(self, request_data: Dict[str, Any], level: str = "INFO"):
        """Log HTTP request data securely"""
        try:
            # Sanitize all values in request data
            sanitized_data = {}
            for key, value in request_data.items():
                if isinstance(value, (dict, list)):
                    sanitized_data[key] = json.dumps(value, separators=(',', ':'))
                else:
                    sanitized_data[key] = self.sanitize_message(str(value))
            
            # Create log message
            log_message = " ".join([f"{k}={v}" for k, v in sanitized_data.items()])
            
            # Log using appropriate level
            if level.upper() == "ERROR":
                self.logger.error(log_message)
            elif level.upper() == "WARNING":
                self.logger.warning(log_message)
            elif level.upper() == "DEBUG":
                self.logger.debug(log_message)
            else:
                self.logger.info(log_message)
                
        except Exception as e:
            # Fallback logging in case of sanitization errors
            fallback_message = f"LOG_ERROR: {str(e)}"
            self.logger.error(fallback_message)
    
    def log_message(self, message: str, level: str = "INFO"):
        """Log a simple message securely"""
        sanitized_message = self.sanitize_message(message)
        
        if level.upper() == "ERROR":
            self.logger.error(sanitized_message)
        elif level.upper() == "WARNING":
            self.logger.warning(sanitized_message)
        elif level.upper() == "DEBUG":
            self.logger.debug(sanitized_message)
        else:
            self.logger.info(sanitized_message)

